@Composable
fun Profile(userId: String, load: suspend (String) -> Unit) {
    LaunchedEffect(userId) { load(userId) }
}

@Composable
fun Timeout(onTimeout: () -> Unit) {
    val latest by rememberUpdatedState(onTimeout)
    LaunchedEffect(Unit) {
        delay(5_000)
        latest()
    }
}

@Composable
fun ConnectivityObserver(source: ConnectivitySource, onChange: (Boolean) -> Unit) {
    val latest by rememberUpdatedState(onChange)
    DisposableEffect(source) {
        val listener = source.addListener { latest(it) }
        onDispose { listener.remove() }
    }
}

@Composable
fun TrackScroll(state: LazyListState, track: (Boolean) -> Unit) {
    LaunchedEffect(state) {
        snapshotFlow { state.firstVisibleItemIndex > 0 }
            .distinctUntilChanged()
            .collect(track)
    }
}

@Composable
fun rememberAvatar(repo: AvatarRepo, id: String): State<Result<Bitmap>> =
    produceState<Result<Bitmap>>(Result.Loading, repo, id) {
        value = repo.load(id)
    }
